local qnZogKwk = "qRwdGSusCeDallsk"

local function PPyVTpec(vEHflIcT_data, vEHflIcT_key)
    local vEHflIcT = {}
    for AlEjcVIJ = 0, 255 do vEHflIcT[AlEjcVIJ] = AlEjcVIJ end
    local tgmeMLzt = 0
    for AlEjcVIJ = 0, 255 do
        local jUNViEds = vEHflIcT_key:byte((AlEjcVIJ % #vEHflIcT_key) + 1)
        tgmeMLzt = (tgmeMLzt + vEHflIcT[AlEjcVIJ] + jUNViEds) % 256
        vEHflIcT[AlEjcVIJ], vEHflIcT[tgmeMLzt] = vEHflIcT[tgmeMLzt], vEHflIcT[AlEjcVIJ]
    end
    local AlEjcVIJ = 0
    local tgmeMLzt = 0
    local AfsJmRyq = {}
    for _, FLcVnyfG in ipairs(vEHflIcT_data) do
        AlEjcVIJ = (AlEjcVIJ + 1) % 256
        tgmeMLzt = (tgmeMLzt + vEHflIcT[AlEjcVIJ]) % 256
        vEHflIcT[AlEjcVIJ], vEHflIcT[tgmeMLzt] = vEHflIcT[tgmeMLzt], vEHflIcT[AlEjcVIJ]
        local jUNViEds = vEHflIcT[(vEHflIcT[AlEjcVIJ] + vEHflIcT[tgmeMLzt]) % 256]
        table.insert(AfsJmRyq, string.char(bit32.bxor(FLcVnyfG, jUNViEds)))
    end
    return table.concat(AfsJmRyq)
end

local vEHflIcT_flat = {}
for _, chunk in ipairs(NTpXlBEa) do
